module shift_register_8bit(clk, reset, load, serial_in, parallel_in, obf_Q);
     input clk;
     input reset;
     input load;
     input serial_in;
     input [7:0] parallel_in;
     output reg [7:0] obf_Q;

     always @(posedge clk) begin
          if (reset)
               obf_Q <= 8'b00000000;
          else if (load)
               obf_Q <= parallel_in;
          else
               obf_Q <= {serial_in, obf_Q[7:1]};
     end
endmodule
